namespace sv_5f3544485bd34a9098fc146f5e68156c.Models;

public class JobApplication
{
    // Step 1: Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    public int CompletedStep { get; set; }
}

public class JobHistoryEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_5f3544485bd34a9098fc146f5e68156c.Models;

namespace sv_5f3544485bd34a9098fc146f5e68156c.Services;

/// <summary>
/// Singleton store for wizard state, keyed by a per-browser session ID cookie.
/// Both the static layout and interactive pages resolve the same instance.
/// </summary>
public class ApplicationStateStore
{
    public const string CookieName = "ApplySessionId";

    private readonly ConcurrentDictionary<string, JobApplication> _store = new();

    public JobApplication GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new JobApplication());
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

