using System.Collections.Concurrent;
using sv_5f3544485bd34a9098fc146f5e68156c.Models;

namespace sv_5f3544485bd34a9098fc146f5e68156c.Services;

/// <summary>
/// Singleton store for wizard state, keyed by a per-browser session ID cookie.
/// Both the static layout and interactive pages resolve the same instance.
/// </summary>
public class ApplicationStateStore
{
    public const string CookieName = "ApplySessionId";

    private readonly ConcurrentDictionary<string, JobApplication> _store = new();

    public JobApplication GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new JobApplication());
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

