@* Static component rendered in the layout — reads state via HttpContext cookie *@
@using sv_5f3544485bd34a9098fc146f5e68156c.Services
@using sv_5f3544485bd34a9098fc146f5e68156c.Models
@inject ApplicationStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

@{
    var steps = new (string Href, string Label)[]
    {
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    };

    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
    int currentStep = Array.FindIndex(steps, s =>
        currentPath.Equals(s.Href, StringComparison.OrdinalIgnoreCase)) + 1;

    bool isWizardPage = currentStep > 0;

    int completedStep = 0;
    if (isWizardPage)
    {
        var ctx = HttpContextAccessor.HttpContext;
        if (ctx is not null && ctx.Request.Cookies.TryGetValue(ApplicationStateStore.CookieName, out var sid) && sid is not null)
        {
            completedStep = Store.GetOrCreate(sid).CompletedStep;
        }
    }
}

@if (isWizardPage)
{
    <nav class="wizard-progress mb-4" aria-label="Application progress">
        <p class="fw-bold mb-2">Step @currentStep of @steps.Length</p>
        <div class="d-flex gap-1 mb-3">
            @for (int i = 0; i < steps.Length; i++)
            {
                var pct = (i < currentStep) ? "100" : "0";
                <div class="progress flex-fill" style="height: 6px;">
                    <div class="progress-bar @(i < completedStep ? "bg-success" : "")"
                         role="progressbar"
                         style="width: @(pct)%"
                         aria-valuenow="@pct" aria-valuemin="0" aria-valuemax="100">
                    </div>
                </div>
            }
        </div>
        <ul class="nav nav-pills gap-2">
            @for (int i = 0; i < steps.Length; i++)
            {
                bool active = (i + 1) == currentStep;
                bool completed = i < completedStep;
                <li class="nav-item">
                    <a class="nav-link @(active ? "active" : "") @(completed && !active ? "text-success" : "")"
                       href="@steps[i].Href">
                        @if (completed && !active)
                        {
                            <span>&#10003; </span>
                        }
                        @steps[i].Label
                    </a>
                </li>
            }
        </ul>
    </nav>
}

