<EditForm Model="model" OnValidSubmit="Next" FormName="personal-info">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="model.Name" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="model.Email" />
    </div>

    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    private PersonalInfoModel model = new();
    private string sessionId = string.Empty;

    private class PersonalInfoModel
    {
        public string Name { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            sessionId = await EnsureSessionId();
            var app = Store.GetOrCreate(sessionId);
            model.Name = app.Name;
            model.Email = app.Email;
            StateHasChanged();
        }
    }

    private async Task Next()
    {
        if (string.IsNullOrEmpty(sessionId))
            sessionId = await EnsureSessionId();

        var app = Store.GetOrCreate(sessionId);
        app.Name = model.Name;
        app.Email = model.Email;
        if (app.CompletedStep < 1) app.CompletedStep = 1;
        Nav.NavigateTo("/apply/experience");
    }

    private async Task<string> EnsureSessionId()
    {
        // Read or create the session cookie via JS interop (interactive component
        // can't access HttpContext, so we use the cookie through the browser).
        var id = await JS.InvokeAsync<string>("eval",
            $"document.cookie.split('; ').find(c => c.startsWith('{ApplicationStateStore.CookieName}='))?.split('=')?.[1]" +
            $" ?? (() => {{ let id = crypto.randomUUID(); document.cookie = '{ApplicationStateStore.CookieName}=' + id + '; path=/; SameSite=Lax'; return id; }})()");
        return id;
    }
}

