@page "/apply/experience"
@rendermode InteractiveServer
@using sv_5f3544485bd34a9098fc146f5e68156c.Models
@using sv_5f3544485bd34a9098fc146f5e68156c.Services
@inject ApplicationStateStore Store
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>Experience — Application</PageTitle>
<h1>Step 2: Work Experience</h1>

@for (int i = 0; i < entries.Count; i++)
{
    var idx = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-start">
            <h5>Position @(idx + 1)</h5>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => entries.RemoveAt(idx)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="entries[idx].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="entries[idx].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="entries[idx].Years" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Position</button>

<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-secondary">&larr; Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<JobHistoryEntry> entries = [];
    private string sessionId = string.Empty;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            sessionId = await EnsureSessionId();
            var app = Store.GetOrCreate(sessionId);
            entries = app.JobHistory.Select(j => new JobHistoryEntry
            {
                Company = j.Company, Title = j.Title, Years = j.Years
            }).ToList();
            if (entries.Count == 0) entries.Add(new());
            StateHasChanged();
        }
    }

    private void AddEntry() => entries.Add(new());

    private async Task Next()
    {
        if (string.IsNullOrEmpty(sessionId))
            sessionId = await EnsureSessionId();

        var app = Store.GetOrCreate(sessionId);
        app.JobHistory = entries.ToList();
        if (app.CompletedStep < 2) app.CompletedStep = 2;
        Nav.NavigateTo("/apply/references");
    }

    private async Task<string> EnsureSessionId()
    {
        var id = await JS.InvokeAsync<string>("eval",
            $"document.cookie.split('; ').find(c => c.startsWith('{ApplicationStateStore.CookieName}='))?.split('=')?.[1]" +
            $" ?? (() => {{ let id = crypto.randomUUID(); document.cookie = '{ApplicationStateStore.CookieName}=' + id + '; path=/; SameSite=Lax'; return id; }})()");
        return id;
    }
}

