            <input class="form-control" @bind="refs[idx].Relationship" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add Reference</button>

<div class="d-flex gap-2">
    <a href="/apply/experience" class="btn btn-secondary">&larr; Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<ReferenceContact> refs = [];
    private string sessionId = string.Empty;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            sessionId = await EnsureSessionId();
            var app = Store.GetOrCreate(sessionId);
            refs = app.References.Select(r => new ReferenceContact
            {
                Name = r.Name, Email = r.Email, Relationship = r.Relationship
            }).ToList();
            if (refs.Count == 0) refs.Add(new());
            StateHasChanged();
        }
    }

    private void AddRef() => refs.Add(new());

    private async Task Next()
    {
        if (string.IsNullOrEmpty(sessionId))
            sessionId = await EnsureSessionId();

        var app = Store.GetOrCreate(sessionId);
        app.References = refs.ToList();
        if (app.CompletedStep < 3) app.CompletedStep = 3;
        Nav.NavigateTo("/apply/review");
    }

    private async Task<string> EnsureSessionId()
    {
        var id = await JS.InvokeAsync<string>("eval",
            $"document.cookie.split('; ').find(c => c.startsWith('{ApplicationStateStore.CookieName}='))?.split('=')?.[1]" +
            $" ?? (() => {{ let id = crypto.randomUUID(); document.cookie = '{ApplicationStateStore.CookieName}=' + id + '; path=/; SameSite=Lax'; return id; }})()");
        return id;
    }
}

