@page "/apply/review"
@rendermode InteractiveServer
@using sv_5f3544485bd34a9098fc146f5e68156c.Models
@using sv_5f3544485bd34a9098fc146f5e68156c.Services
@inject ApplicationStateStore Store
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>Review — Application</PageTitle>
<h1>Step 4: Review Your Application</h1>

@if (app is null)
{
    <p>Loading...</p>
}
else
{
    <section class="mb-4">
        <h4>Personal Information</h4>
        <dl class="row">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@app.Name</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@app.Email</dd>
        </dl>
    </section>

    <section class="mb-4">
        <h4>Work Experience</h4>
        @if (app.JobHistory.Count == 0)
        {
            <p class="text-muted">No entries.</p>
        }
        else
        {
            <table class="table">
                <thead><tr><th>Company</th><th>Title</th><th>Years</th></tr></thead>
                <tbody>
                    @foreach (var j in app.JobHistory)
                    {
                        <tr><td>@j.Company</td><td>@j.Title</td><td>@j.Years</td></tr>
                    }
                </tbody>
            </table>
        }
    </section>

    <section class="mb-4">
        <h4>References</h4>
        @if (app.References.Count == 0)
        {
            <p class="text-muted">No references.</p>
        }
        else
        {
            <table class="table">
                <thead><tr><th>Name</th><th>Email</th><th>Relationship</th></tr></thead>
                <tbody>
                    @foreach (var r in app.References)
                    {
                        <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                    }
                </tbody>
            </table>
        }
    </section>

    <div class="d-flex gap-2">
        <a href="/apply/references" class="btn btn-secondary">&larr; Back</a>
        <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-3">Your application has been submitted!</div>
    }
}

@code {
    private JobApplication? app;
    private string sessionId = string.Empty;
    private bool submitted;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            sessionId = await EnsureSessionId();
            app = Store.GetOrCreate(sessionId);
            StateHasChanged();
        }
    }

    private void Submit()
    {
        submitted = true;
        if (!string.IsNullOrEmpty(sessionId))
        {
            var a = Store.GetOrCreate(sessionId);
            if (a.CompletedStep < 4) a.CompletedStep = 4;
        }
    }

    private async Task<string> EnsureSessionId()
    {
        var id = await JS.InvokeAsync<string>("eval",
            $"document.cookie.split('; ').find(c => c.startsWith('{ApplicationStateStore.CookieName}='))?.split('=')?.[1]" +
            $" ?? (() => {{ let id = crypto.randomUUID(); document.cookie = '{ApplicationStateStore.CookieName}=' + id + '; path=/; SameSite=Lax'; return id; }})()");
        return id;
    }
}

